{
  "sql": "SELECT id, name, email, phone FROM res_partner WHERE customer_rank > 0 ORDER BY id DESC LIMIT 20"
}

{
  "sql": "SELECT pt.id, pt.name, pt.list_price, pt.default_code FROM product_template pt WHERE pt.sale_ok = true ORDER BY pt.id LIMIT 50"
}

{
  "sql": "SELECT SUM(-aml.balance) AS net_sales FROM account_move_line aml JOIN account_move am ON am.id = aml.move_id WHERE am.move_type IN ('out_invoice','out_refund') AND am.state = 'posted' AND aml.exclude_from_invoice_tab = false AND aml.display_type IS NULL AND date_trunc('month', am.invoice_date) = date_trunc('month', (now() AT TIME ZONE 'Asia/Bangkok')::date)"
}

{
  "sql": "SELECT pt.name, SUM(sq.quantity) AS on_hand FROM stock_quant sq JOIN product_product pp ON pp.id = sq.product_id JOIN product_template pt ON pt.id = pp.product_tmpl_id WHERE sq.location_id IN (SELECT id FROM stock_location WHERE usage = 'internal') GROUP BY pt.name ORDER BY on_hand DESC LIMIT 50"
}
